    const v = String(h).trim();

    if (/^\d{1,2}$/.test(v)) return v.padStart(2,'0') + ':00:00';
    if (/^\d{1,2}:\d{2}$/.test(v)) return v.padStart(5,'0') + ':00';
    if (/^\d{1,2}:\d{2}:\d{2}$/.test(v)) return v.padStart(8,'0');

    return null;
}

