function parseAnvizJSON(text) {
    if (typeof text !== 'string') return text;
    text = text.trim();

    try {
        return JSON.parse(text);
    } catch(e) {}

    let cleaned = text.replace(/,\s*}/g, '}');
    cleaned = cleaned.replace(/,\s*]/g, ']');
    cleaned = cleaned.replace(/([{,]\s*)([a-zA-Z_][a-zA-Z0-9_]*)\s*:/g, '$1"$2":');
    cleaned = cleaned.replace(/'/g, '"');
    cleaned = cleaned.replace(/[\x00-\x1F\x7F-\x9F]/g, '');

    try {
        return JSON.parse(cleaned);
    } catch(e) {
        const jsonMatch = cleaned.match(/\{[\s\S]*\}/);
        if (jsonMatch) {
            try {
                return JSON.parse(jsonMatch[0]);
            } catch(e2) {}
        }
        throw new Error(`No se pudo parsear JSON: ${e.message}`);
    }
}

// Función para marcar reloj como fallido y pasar al siguiente
function marcarFalloYContinuar(errorMsg) {
    const readerIp = flow.get('readerIp');
    const faseReintento = flow.get('faseReintento') || false;
    const estadoRelojes = flow.get('estadoRelojes') || [];
    const estadoReloj = estadoRelojes.find(r => r.ip === readerIp);

    if (estadoReloj) {
        estadoReloj.estado = faseReintento ? 'FALLIDO_DEFINITIVO' : 'FALLIDO_PRIMERA';
        estadoReloj.error = errorMsg;
        estadoReloj.duracion = Math.round((Date.now() - flow.get('inicioRelojActual')) / 1000);
        flow.set('estadoRelojes', estadoRelojes);
    }

    // Si NO es fase de reintento, agregar a lista de reintento
    if (!faseReintento) {
        const relojesParaReintento = flow.get('relojesParaReintento') || [];
        const relojActual = flow.get('relojActual');
        if (relojActual && !relojesParaReintento.find(r => r.ip === relojActual.ip)) {
            relojesParaReintento.push(relojActual);
            flow.set('relojesParaReintento', relojesParaReintento);
        }
    }

    // Pasar al siguiente reloj
    const relojActualIndex = flow.get('relojActualIndex') || 0;
    flow.set('relojActualIndex', relojActualIndex + 1);

    setTimeout(() => {
        node.send([null, { payload: 'siguiente_reloj' }]);
    }, 2000);
}

