        flow.set('esUltimoBatch', true);
        flow.set('todosLosRegistros', []);
        flow.set('registroIndex', 0);

        return [msg, null];
    }

    // Guardar registros del batch actual
    flow.set('todosLosRegistros', records);
    flow.set('registroIndex', 0);

    node.log(`📦 [${msg.readerIp}] Batch ${batchIndex + 1}: ${records.length} registros obtenidos`);

    // Si obtuvimos menos que el batchSize, es el último batch
    if (records.length < batchSize) {
        flow.set('esUltimoBatch', true);
    } else {
        flow.set('esUltimoBatch', false);
    }

    return [msg, null];

