    const parts = str.split(':');
    if (parts.length < 2) return null; // debe tener al menos HH:MM
    const h = String(parts[0] || 0).padStart(2,'0');
    const m = String(parts[1] || 0).padStart(2,'0');
    const s = parts[2] ? String(parts[2]).padStart(2,'0') : '00';
    return `${h}:${m}:${s}`;
}

