// Convierte Date | "17/10/2025" | "2025-10-17" → "YYYY-MM-DD"
function parseDateMySQL(str) {
    if (!str) return null;

    if (str instanceof Date) {
        if (isNaN(str)) return null;
        return str.toISOString().slice(0, 10);
    }

    const s = String(str);

    if (s.includes('/')) {
        const [d, m, y] = s.split('/');
        if (!d || !m || !y) return null;
        return `${y}-${m.padStart(2, '0')}-${d.padStart(2, '0')}`;
    }

    if (s.includes('-')) {
        return s.slice(0, 10);
    }

    return null;
}

// Convierte "7" | "07" | "07:00" | "07:00:00" → "HH:MM:SS"
function parseTimeMySQL(str) {
    if (str === null || str === undefined) return null;

    const s = String(str).trim();
    if (!s) return null;

    if (!s.includes(':')) {
        const h = s.padStart(2, '0');
        return `${h}:00:00`;
    }

    const parts = s.split(':');
    const h = parts[0].padStart(2, '0');
    const m = (parts[1] || '00').padStart(2, '0');
    const sec = (parts[2] || '00').padStart(2, '0');

    return `${h}:${m}:${sec}`;
}

