function parseDate(val) {
    if (val === null || val === undefined || val === '' || val === 'null') return null;

    if (val instanceof Date) {
        // Si es fecha inválida, devolver null en vez de "Invalid Date"
        if (isNaN(val.getTime())) return null;
        return val.toISOString().slice(0, 10);
    }

    if (typeof val === "string") {
        val = val.trim();
        if (val === '') return null;

        if (val.includes("T")) return val.slice(0, 10);

        // Formato DD/MM/YYYY o DD/MM/YY
        if (val.includes("/")) {
            const parts = val.split("/");
            if (parts.length === 3) {
                let [d, m, y] = parts;
                // Año de 2 dígitos → 20xx
                if (y.length === 2) y = "20" + y;
                return `${y}-${m.padStart(2, '0')}-${d.padStart(2, '0')}`;
            }
        }

        // Formato YYYY-MM-DD directo
        if (/^\d{4}-\d{2}-\d{2}/.test(val)) return val.slice(0, 10);
    }

    node.warn(`parseDate: valor no reconocido → "${val}" (tipo: ${typeof val})`);
    return null;
}

function parseTime(val) {
    if (val === null || val === undefined || val === '' || val === 'null') return null;
    const str = String(val).trim();
    if (str === '') return null;
    const p = str.split(":");
    if (p.length < 2) return null;
    return `${p[0].padStart(2, '0')}:${p[1].padStart(2, '0')}:${(p[2] || '00').padStart(2, '0')}`;
}

function parseNum(val, defaultVal = 0) {
    if (val === null || val === undefined || val === '') return defaultVal;
    const n = Number(val);
    return isNaN(n) ? defaultVal : n;
}

