function val(tag, dec = 2) {
  let x = v[tag];
  if (!x) return "-";

  if (typeof x === "object") {
    let value = Number(x.value);
    if (!Number.isFinite(value)) return "-";
    return value.toFixed(dec) + " " + (x.unit || "");
  }

  x = Number(x);
  if (!Number.isFinite(x)) return "-";
  return x.toFixed(dec);
}

