let ph = num(fabrica, "Clarificacion3.Clarificacion3.clar3_encalado_ph");
let nivelFosa = num(fabrica, "fabrica_bb.fabrica_bb.Fab_agua_industrial_nivel");
let meladoTratado = num(fabrica, "tacho2da3ra.tacho2da3ra.Tacho_melado_tratado");

let alertas = [];

if (ph > 7.4) {
    alertas.push("pH de encalado alto, con valor de " + ph.toFixed(2));
}

if (ph > 0 && ph < 6.5) {
    alertas.push("pH de encalado bajo, con valor de " + ph.toFixed(2));
}

if (nivelFosa > 0 && nivelFosa < 75) {
    alertas.push("nivel de fosa bajo, con " + nivelFosa.toFixed(1) + " por ciento");
}

if (meladoTratado > 85) {
    alertas.push("nivel de melado tratado alto, con " + meladoTratado.toFixed(1) + " por ciento");
}

function textoAlertas() {
    if (alertas.length === 0) {
        return "No se registran alarmas críticas en los puntos supervisados.";
    }

    return "Atención. Se registran las siguientes condiciones: " + alertas.join("; ") + ".";
}

