        "El nivel de fosa es " + val(fabrica, "fabrica_bb.fabrica_bb.Fab_agua_industrial_nivel") + ". " +
        "El nivel de melado tratado es " + val(fabrica, "tacho2da3ra.tacho2da3ra.Tacho_melado_tratado") + ". " +
        textoAlertas() + " " +
        "Fin del informe general.";

    return cerrar(texto);
}

// ===============================
// TRAPICHE
// ===============================

if (sector === "trapiche") {
    let texto =
